diff --git a/crates/mu-coding/src/serve/forwarder.rs b/crates/mu-coding/src/serve/forwarder.rs
--- a/crates/mu-coding/src/serve/forwarder.rs
+++ b/crates/mu-coding/src/serve/forwarder.rs
@@ -463,15 +463,11 @@ fn compute_status(
     // Context pressure from the last model call's total input tokens.
     if let Some(last_input) = last_call_input {
         status.last_call_context_tokens = Some(last_input);
-        let window = context_window_for(&provider_kind, &model)
-            .unwrap_or(mu_core::agent::DEFAULT_COMPACTION_THRESHOLD as u64);
-        status.context_window_size = Some(window);
-        status.context_pressure_pct = Some((last_input as f64 / window as f64) * 100.0);
+        let window = context_window_for(&provider_kind, &model);
+        if let Some(w) = window {
+            status.context_window_size = Some(w);
+            status.context_pressure_pct = Some((last_input as f64 / w as f64) * 100.0);
+        }
     }

     status

diff --git a/src/disk_status.rs b/src/disk_status.rs
--- a/src/disk_status.rs
+++ b/src/disk_status.rs
@@ -10,12 +10,16 @@ struct DiskStatus {
     used_bytes: u64,
     capacity_bytes: Option<u64>,
     usage_pct: Option<f64>,
 }

+const DEFAULT_QUOTA_BYTES: u64 = 100_000_000_000;
+
 fn compute_disk_status(mount: &Mount, used: u64) -> DiskStatus {
     let mut status = DiskStatus::default();
     status.used_bytes = used;
-    // capacity_for() returns None for network/overlay mounts not in the table.
-    if let Some(cap) = capacity_for(mount) {
-        status.capacity_bytes = Some(cap);
-        status.usage_pct = Some((used as f64 / cap as f64) * 100.0);
-    }
+    // capacity_for() returns None for network/overlay mounts not in the
+    // table; fall back to the default quota so the gauge is never blank.
+    let cap = capacity_for(mount);
+    if let Some(c) = cap {
+        status.capacity_bytes = Some(c);
+        status.usage_pct = Some((used as f64 / c as f64) * 100.0);
+    }
     status
 }
